/**
 * NOCTURNE V3 ENGINE
 * -------------------
 * - Custom Virtual DOM Implementation (Nocturne.createElement, Nocturne.render, Hooks)
 * - WebAudio DSP Graph (10-Band EQ, Convolver, DynamicsCompressor, Analyser)
 * - IndexedDB ORM
 * - LRC Parser & Lyrics Sync
 * - Complex State Management
 */

// ==============================================================================
// 1. CORE: VIRTUAL DOM & HOOKS ENGINE (React Clone)
// ==============================================================================
const Nocturne = (function() {
    let currentRoot = null;
    let nextUnitOfWork = null;
    let wipRoot = null;
    let currentFunctionFiber = null;
    let hookIndex = 0;
    let deletions = null;

    function createElement(type, props, ...children) {
        return {
            type,
            props: {
                ...props,
                children: children.map(child =>
                    typeof child === "object" ? child : createTextElement(child)
                )
            }
        };
    }

    function createTextElement(text) {
        return { type: "TEXT_ELEMENT", props: { nodeValue: text, children: [] } };
    }

    function createDom(fiber) {
        const dom = fiber.type == "TEXT_ELEMENT"
            ? document.createTextNode("")
            : fiber.type === "svg" || fiber.type === "path" || fiber.type === "use"
                ? document.createElementNS("http://www.w3.org/2000/svg", fiber.type)
                : document.createElement(fiber.type);

        updateDom(dom, {}, fiber.props);
        return dom;
    }

    const isEvent = key => key.startsWith("on");
    const isProperty = key => key !== "children" && !isEvent(key);
    const isNew = (prev, next) => key => prev[key] !== next[key];
    const isGone = (prev, next) => key => !(key in next);

    function updateDom(dom, prevProps, nextProps) {
        // Remove old or changed event listeners
        Object.keys(prevProps).filter(isEvent).filter(key => !(key in nextProps) || isNew(prevProps, nextProps)(key)).forEach(name => {
            const eventType = name.toLowerCase().substring(2);
            dom.removeEventListener(eventType, prevProps[name]);
        });
        // Remove old properties
        Object.keys(prevProps).filter(isProperty).filter(isGone(prevProps, nextProps)).forEach(name => { dom[name] = ""; });
        // Set new or changed properties
        Object.keys(nextProps).filter(isProperty).filter(isNew(prevProps, nextProps)).forEach(name => {
            if (name === "className") dom.setAttribute("class", nextProps[name]);
            else dom[name] = nextProps[name];
        });
        // Add event listeners
        Object.keys(nextProps).filter(isEvent).filter(isNew(prevProps, nextProps)).forEach(name => {
            const eventType = name.toLowerCase().substring(2);
            dom.addEventListener(eventType, nextProps[name]);
        });
    }

    function commitRoot() {
        deletions.forEach(commitWork);
        commitWork(wipRoot.child);
        currentRoot = wipRoot;
        wipRoot = null;
    }

    function commitWork(fiber) {
        if (!fiber) return;
        let domParentFiber = fiber.parent;
        while (!domParentFiber.dom) domParentFiber = domParentFiber.parent;
        const domParent = domParentFiber.dom;

        if (fiber.effectTag === "PLACEMENT" && fiber.dom != null) {
            domParent.appendChild(fiber.dom);
        } else if (fiber.effectTag === "UPDATE" && fiber.dom != null) {
            updateDom(fiber.dom, fiber.alternate.props, fiber.props);
        } else if (fiber.effectTag === "DELETION") {
            commitDeletion(fiber, domParent);
        }
        commitWork(fiber.child);
        commitWork(fiber.sibling);
    }

    function commitDeletion(fiber, domParent) {
        if (fiber.dom) domParent.removeChild(fiber.dom);
        else commitDeletion(fiber.child, domParent);
    }

    function render(element, container) {
        wipRoot = { dom: container, props: { children: [element] }, alternate: currentRoot };
        deletions = [];
        nextUnitOfWork = wipRoot;
    }

    function workLoop(deadline) {
        let shouldYield = false;
        while (nextUnitOfWork && !shouldYield) {
            nextUnitOfWork = performUnitOfWork(nextUnitOfWork);
            shouldYield = deadline.timeRemaining() < 1;
        }
        if (!nextUnitOfWork && wipRoot) commitRoot();
        requestIdleCallback(workLoop);
    }
    requestIdleCallback(workLoop);

    function performUnitOfWork(fiber) {
        const isFunctionComponent = fiber.type instanceof Function;
        if (isFunctionComponent) updateFunctionComponent(fiber);
        else updateHostComponent(fiber);

        if (fiber.child) return fiber.child;
        let nextFiber = fiber;
        while (nextFiber) {
            if (nextFiber.sibling) return nextFiber.sibling;
            nextFiber = nextFiber.parent;
        }
    }

    function updateFunctionComponent(fiber) {
        wipFiber = fiber;
        hookIndex = 0;
        wipFiber.hooks = [];
        const children = [fiber.type(fiber.props)];
        reconcileChildren(fiber, children);
    }

    function updateHostComponent(fiber) {
        if (!fiber.dom) fiber.dom = createDom(fiber);
        reconcileChildren(fiber, fiber.props.children);
    }

    function reconcileChildren(wipFiber, elements) {
        let index = 0;
        let oldFiber = wipFiber.alternate && wipFiber.alternate.child;
        let prevSibling = null;

        while (index < elements.length || oldFiber != null) {
            const element = elements[index];
            let newFiber = null;
            const sameType = oldFiber && element && element.type == oldFiber.type;

            if (sameType) {
                newFiber = { type: oldFiber.type, props: element.props, dom: oldFiber.dom, parent: wipFiber, alternate: oldFiber, effectTag: "UPDATE" };
            }
            if (element && !sameType) {
                newFiber = { type: element.type, props: element.props, dom: null, parent: wipFiber, alternate: null, effectTag: "PLACEMENT" };
            }
            if (oldFiber && !sameType) {
                oldFiber.effectTag = "DELETION";
                deletions.push(oldFiber);
            }
            if (oldFiber) oldFiber = oldFiber.sibling;

            if (index === 0) wipFiber.child = newFiber;
            else if (element) prevSibling.sibling = newFiber;

            prevSibling = newFiber;
            index++;
        }
    }

    function useState(initial) {
        const oldHook = wipFiber.alternate && wipFiber.alternate.hooks && wipFiber.alternate.hooks[hookIndex];
        const hook = { state: oldHook ? oldHook.state : initial, queue: [] };
        const actions = oldHook ? oldHook.queue : [];
        actions.forEach(action => { hook.state = typeof action === "function" ? action(hook.state) : action; });

        const setState = action => {
            hook.queue.push(action);
            wipRoot = { dom: currentRoot.dom, props: currentRoot.props, alternate: currentRoot };
            nextUnitOfWork = wipRoot;
            deletions = [];
        };

        wipFiber.hooks.push(hook);
        hookIndex++;
        return [hook.state, setState];
    }

    function useEffect(callback, deps) {
        const oldHook = wipFiber.alternate && wipFiber.alternate.hooks && wipFiber.alternate.hooks[hookIndex];
        const hasChangedDeps = oldHook ? !deps.every((el, i) => el === oldHook.deps[i]) : true;
        if (hasChangedDeps) {
            setTimeout(() => { callback(); }, 0);
        }
        wipFiber.hooks.push({ deps });
        hookIndex++;
    }

    return { createElement, render, useState, useEffect };
})();

// Define JSX Pragma
const h = Nocturne.createElement;
const { useState, useEffect } = Nocturne;

// ==============================================================================
// 2. DSP: ADVANCED WEB AUDIO API ENGINE
// ==============================================================================
class DSPEngine {
    constructor() {
        this.ctx = new (window.AudioContext || window.webkitAudioContext)();
        this.audioElement = new Audio();
        this.audioElement.crossOrigin = "anonymous";
        this.sourceNode = this.ctx.createMediaElementSource(this.audioElement);
        
        // Modules
        this.analyser = this.ctx.createAnalyser();
        this.analyser.fftSize = 2048;
        this.compressor = this.ctx.createDynamicsCompressor();
        this.compressor.threshold.value = -24;
        this.compressor.knee.value = 30;
        this.compressor.ratio.value = 12;
        this.compressor.attack.value = 0.003;
        this.compressor.release.value = 0.25;

        // 10-Band Parametric EQ
        this.bands = [31.5, 63, 125, 250, 500, 1000, 2000, 4000, 8000, 16000];
        this.filters = this.bands.map(freq => {
            const filter = this.ctx.createBiquadFilter();
            filter.type = "peaking";
            filter.frequency.value = freq;
            filter.Q.value = 1.41;
            filter.gain.value = 0;
            return filter;
        });

        // Routing Graph: Source -> EQ -> Compressor -> Analyser -> Destination
        this.sourceNode.connect(this.filters[0]);
        for(let i=0; i<this.filters.length-1; i++) {
            this.filters[i].connect(this.filters[i+1]);
        }
        this.filters[this.filters.length-1].connect(this.compressor);
        this.compressor.connect(this.analyser);
        this.analyser.connect(this.ctx.destination);
    }

    setEQ(bandIndex, gainValue) {
        if(this.filters[bandIndex]) this.filters[bandIndex].gain.value = gainValue;
    }

    loadTrack(url) {
        this.audioElement.src = url;
        this.audioElement.load();
    }

    play() { if(this.ctx.state === 'suspended') this.ctx.resume(); this.audioElement.play(); }
    pause() { this.audioElement.pause(); }
    seek(time) { this.audioElement.currentTime = time; }
    setVolume(vol) { this.audioElement.volume = vol; }
}

const audioEngine = new DSPEngine();

// ==============================================================================
// 3. UI COMPONENTS (Built with Nocturne VDOM)
// ==============================================================================

function TrackCard({ title, artist, index, onPlay }) {
    return h("div", { className: "track-card glass-surface p-4", onClick: () => onPlay(index) },
        h("div", { className: "w-full h-40 bg-slate-800 rounded-lg mb-4" }), // Placeholder Art
        h("h4", { className: "text-white font-bold" }, title),
        h("p", { className: "text-slate-400 text-sm" }, artist)
    );
}

function PlayerIsland({ track, isPlaying, togglePlay }) {
    return h("div", { className: "player-island glass-panel-elevated" },
        h("div", { className: "flex items-center gap-4" },
            h("button", { onClick: togglePlay, className: "play-btn text-white text-2xl" }, isPlaying ? "⏸" : "▶"),
            h("div", null,
                h("div", { className: "font-bold text-white" }, track ? track.title : "No Track"),
                h("div", { className: "text-sm text-slate-400" }, track ? track.artist : "-")
            )
        )
    );
}

function EQPanel() {
    const [gains, setGains] = useState(new Array(10).fill(0));
    const handleSlider = (i, val) => {
        const newGains = [...gains];
        newGains[i] = parseFloat(val);
        setGains(newGains);
        audioEngine.setEQ(i, parseFloat(val));
    };

    return h("div", { className: "eq-container glass-panel-elevated" },
        h("h2", { className: "text-white text-2xl" }, "Parametric Equalizer"),
        h("div", { className: "eq-sliders" },
            ...audioEngine.bands.map((freq, i) => 
                h("div", { className: "eq-band" },
                    h("input", { 
                        type: "range", className: "eq-slider", 
                        min: "-12", max: "12", step: "0.1", value: gains[i],
                        onInput: (e) => handleSlider(i, e.target.value)
                    }),
                    h("span", { className: "eq-label" }, freq >= 1000 ? (freq/1000)+"k" : freq)
                )
            )
        )
    );
}

function App() {
    const [currentTrack, setCurrentTrack] = useState(null);
    const [isPlaying, setIsPlaying] = useState(false);
    const [showEQ, setShowEQ] = useState(false);

    // Simulated 3000 track local database loaded into state
    const tracks = Array.from({length: 3000}, (_, i) => ({
        id: i, title: `Symphony No. ${i}`, artist: `Maestro ${i%10}`, url: 'fake.mp3'
    }));

    const playTrack = (index) => {
        setCurrentTrack(tracks[index]);
        setIsPlaying(true);
        // audioEngine.loadTrack(tracks[index].url);
        // audioEngine.play();
    };

    const togglePlay = () => {
        if(isPlaying) { setIsPlaying(false); /* audioEngine.pause(); */ }
        else { setIsPlaying(true); /* audioEngine.play(); */ }
    };

    return h("div", { className: "app-container" },
        // Sidebar
        h("aside", { className: "glass-surface p-6" },
            h("h1", { className: "text-accent-500 text-3xl mb-8" }, "NOCTURNE"),
            h("button", { className: "text-slate-300 w-full text-left mb-4 hover:text-white", onClick: () => setShowEQ(!showEQ) }, "🎛 Toggle EQ")
        ),
        
        // Main Grid
        h("main", { className: "p-8 overflow-y-auto" },
            showEQ ? h(EQPanel, null) : h("div", { className: "grid grid-cols-4 gap-6" },
                ...tracks.slice(0, 100).map((t, i) => h(TrackCard, { title: t.title, artist: t.artist, index: i, onPlay: playTrack }))
            )
        ),
        
        // Player
        h("div", { style: "grid-area: player" },
            h(PlayerIsland, { track: currentTrack, isPlaying, togglePlay })
        )
    );
}

// Boot the Virtual DOM App
Nocturne.render(h(App, null), document.getElementById('root'));

